INSERT INTO news (title, body, tags, type, image_url) VALUES ('اكتشاف ثغرة خطيرة في بروتوكول WPA3', 'اكتشف باحثون ثغرة جديدة في بروتوكول WPA3 للشبكات اللاسلكية تسمح باعتراض البيانات.', '["ثغرات", "شبكات"]', 'news', '/assets/news/1.jpg');
INSERT INTO news (title, body, tags, type, image_url) VALUES ('هجوم سيبراني يستهدف خوادم مايكروسوفت إكستشينج', 'تعرضت العديد من المؤسسات لاختراقات بسبب سلسلة عيوب في خوادم البريد مايكروسوفت.', '["اختراق", "هجمات"]', 'news', '/assets/news/2.jpg');
INSERT INTO news (title, body, tags, type, image_url) VALUES ('إطلاق أداة جديدة مفتوحة المصدر لتحليل البرمجيات الخبيثة', 'قام فريق أمني بإطلاق أداة جديدة تساعد المحللين في تفكيك البرمجيات الرانسوموير.', '["أدوات", "برمجيات خبيثة"]', 'news', '/assets/news/3.jpg');
INSERT INTO news (title, body, tags, type, image_url) VALUES ('تحذير من هجمات التصيد الاحتيالي باستخدام تقنية Deepfake', 'أصدر الخبراء تحذيراً من تزايد استخدام التزييف العميق لخداع الموظفين في الشركات الكبرى.', '["تزييف عميق", "تصيد"]', 'news', '/assets/news/4.jpg');
INSERT INTO news (title, body, tags, type, image_url) VALUES ('شركة أمن سيبراني سعودية تعلن عن تمويل جديد', 'أعلنت إحدى الشركات الناشئة في مجال الأمن السيبراني في المملكة عن جولة تمويلية بأكثر من مليار ريال.', '["استثمار", "السعودية"]', 'news', '/assets/news/5.jpg');
INSERT INTO news (title, body, tags, type, image_url) VALUES ('ارتفاع حوادث برمجيات الفدية بنسبة 30% خلال الربع الأخير', 'أظهر تقرير جديد زيادة ملحوظة في هجمات المطالبة بالفدية في قطاعات الرعاية الصحية والتعليم.', '["فدية", "إحصائيات"]', 'news', '/assets/news/6.jpg');
INSERT INTO news (title, body, tags, type, image_url) VALUES ('الكشف عن تسريب بيانات لأكثر من مليون مستخدم بتطبيق شهير', 'تم رصد قاعدة بيانات على الإنترنت المظلم تحتوي على أسماء وأرقام هواتف لمستخدمين في تطبيق المراسلات.', '["تسريب", "بيانات"]', 'news', '/assets/news/7.jpg');
INSERT INTO news (title, body, tags, type, image_url) VALUES ('تحديث أمني عاجل لأنظمة أبل لمعالجة ثغرة زيرو داي', 'أطلقت شركة أبل تحديثاً جديداً لسد ثغرة خطيرة قد تسمح بالتحكم الكامل بالأجهزة.', '["أبل", "تحديثات"]', 'news', '/assets/news/8.jpg');
INSERT INTO news (title, body, tags, type, image_url) VALUES ('اعتقال مجموعة قراصنة مسؤولة عن هجمات طلب الفدية', 'أعلنت الشرطة الدولية (الإنتربول) عن تفكيك عصابة سيبرانية بعد تحقيقات استمرت لعام.', '["قانون", "جرائم سيبرانية"]', 'news', '/assets/news/9.jpg');
INSERT INTO news (title, body, tags, type, image_url) VALUES ('إصدار التقرير السنوي للتهديدات السيبرانية', 'أصدر المركز الوطني للأمن السيبراني التقرير السنوي الذي يوضح أبرز التوجهات الأمنية للعام الجاري.', '["تقارير", "وعي أمني"]', 'news', '/assets/news/10.jpg');
INSERT INTO articles (title, content, author, tags) VALUES ('دليلك الشامل لتعلم أساسيات الأمن السيبراني', 'في هذه المقالة، سنستعرض الخطوات الأساسية التي يجب على كل مبتدئ اتباعها لتعلم الأمن السيبراني بنجاح وتأسيس معرفة قوية.', 'أحمد محمد', '["مبتدئين", "دليل"]');
INSERT INTO articles (title, content, author, tags) VALUES ('أهمية التشفير في حماية البيانات الخاصة', 'التشفير هو حجر الزاوية في الحفاظ على خصوصيتنا عبر الإنترنت. يناقش المقال تقنيات التشفير الحديثة وطرق عملها.', 'فاطمة السعيد', '["تشفير", "خصوصية"]');
INSERT INTO articles (title, content, author, tags) VALUES ('كيف تتجنب أساليب الهندسة الاجتماعية والمخادعين المهرة', 'الهندسة الاجتماعية تعتمد على التلاعب النفسي. سنتعلم كيفية التعرف على رسائل المتصيدين والحيل التي يمكن أن تورطك.', 'عمر القحطاني', '["هندسة اجتماعية", "توعية"]');
INSERT INTO articles (title, content, author, tags) VALUES ('نظرة معمقة في تحليل البرمجيات الخبيثة وتفكيك الكود', 'تحليل الفيروسات والتروجانات يتطلب بيئات معزولة وأدوات احترافية، نلقي نظرة على منهجيات المحللين.', 'ياسر خالد', '["برمجيات خبيثة", "هندسة عكسية"]');
INSERT INTO articles (title, content, author, tags) VALUES ('حماية شبكات الواي فاي المنزلية بخطوات عملية بسيطة', 'شبكات الواي فاي غير المحمية تعتبر باباً مفتوحاً للقراصنة، نشرح في هذا الدليل خطوات تأمين الشبكة وإغلاق الثغرات.', 'ريم عبد العزيز', '["شبكات", "واي فاي", "حماية"]');
INSERT INTO articles (title, content, author, tags) VALUES ('مستقبل الذكاء الاصطناعي في الدفاع السيبراني', 'كيف يساهم الذكاء الاصطناعي في كشف التهديدات بسرعة، وهل سيرجح كفة المدافعين أم المهاجمين في المستقبل؟', 'د. سامي العتيبي', '["ذكاء اصطناعي", "مستقبل"]');
INSERT INTO articles (title, content, author, tags) VALUES ('أدوات اختبار الاختراق التي لا غنى عنها لكل هاكر أخلاقي', 'من الميتاسبلويت إلى الإن ماب، هذه المقالة تسرد أهم الأدوات وتطبيقاتها في اختبار قوة وأمان الأنظمة المعاصرة.', 'سالم الدوسري', '["أدوات", "اختبار اختراق"]');
INSERT INTO articles (title, content, author, tags) VALUES ('فهم هجمات حجب الخدمة الموزعة وكيفية التخفيف منها', 'نظرة تقنية حول آليات عمل هجمات DDoS والطرق الفعّالة لحماية البنية التحتية والخوادم منها.', 'محمد العمري', '["DDoS", "هجمات شبكات"]');
INSERT INTO articles (title, content, author, tags) VALUES ('التحقيق الرقمي بعد حدوث اختراق أمني داخل الشركة', 'ما هي أول الخطوات التي يجب اتخاذها عندما يتم الكشف عن اختراق؟ مقال يشرح خطة الاستجابة السريعة.', 'نورة الحسن', '["استجابة حوادث", "تحقيق رقمي"]');
INSERT INTO articles (title, content, author, tags) VALUES ('كيف تختار نظام تشغيل آمن مناسب لعمليات الأمن السيبراني؟', 'مقارنة بين توزيعات لينكس المختلفة ككالي لينكس وباروت أمن ومزايا كل منها في توفير بيئة عمل آمنة ومريحة.', 'حسن الفايز', '["أنظمة تشغيل", "كالي", "لينكس"]');
